(function () {
  "use strict";
  const OA=window.OrbArena, esc=(value)=>String(value??"").replace(/[&<>"']/g,(char)=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[char]));
  const STEPS=["Modo","Times","Personagens","Builds","Habilidades","Perks","Arena","Modificadores","Resumo"];
  class DraftUI {
    constructor(app){this.app=app;this.step=0;this.data={gameModeId:"orb",modeId:"1v1",arenaId:"classic",arenaSize:"small",durationPreset:"standard",modifiers:[],controlMode:"AUTO",characterId:app.state.settings.characterId||"echo",enemyCharacterId:"singularity",weaponId:"arc-cannon",perks:[],abilities:{}};this.ensure();}
    ensure(){
      const section=document.createElement("section");section.className="screen remaster-screen";section.id="screen-draft";
      section.innerHTML=`<div class="remaster-page draft-page"><header class="remaster-head"><button class="back-button" data-draft-home>← MENU</button><div><span class="eyebrow">PROTOCOLO DE FORMAÇÃO</span><h1>DRAFT DE BATALHA</h1><p>Nove etapas, regras verificáveis e resumo antes do lançamento.</p></div><button class="button button-secondary" data-save-draft>SALVAR PRESET</button></header><nav class="draft-steps"></nav><div class="draft-stage panel"></div><footer class="draft-footer"><button class="button button-secondary" data-draft-prev>← VOLTAR</button><div class="draft-budget"></div><button class="button button-primary" data-draft-next>AVANÇAR →</button></footer></div>`;
      document.querySelector(".screen-stack").appendChild(section);this.root=section;
      section.querySelector("[data-draft-home]").onclick=()=>app.goHome();section.querySelector("[data-draft-prev]").onclick=()=>{this.step=Math.max(0,this.step-1);this.render();};section.querySelector("[data-draft-next]").onclick=()=>this.next();section.querySelector("[data-save-draft]").onclick=()=>this.save();
    }
    open(){this.step=0;const saved=this.app.storage.read().presets.drafts[0];if(saved)this.data={...this.data,...structuredClone(saved.data||saved)};this.app.showScreen("draft");this.render();}
    mode(){return OA.MATCH_MODES[this.data.modeId]||OA.MATCH_MODES["1v1"];}
    teamCount(){return this.mode().sides.reduce((sum,value)=>sum+value,0);}
    render(){
      this.root.querySelector(".draft-steps").innerHTML=STEPS.map((label,index)=>`<button class="${index===this.step?"active":""} ${index<this.step?"done":""}" data-step="${index}"><b>${index+1}</b><span>${label}</span></button>`).join("");
      this.root.querySelectorAll("[data-step]").forEach((button)=>button.onclick=()=>{if(+button.dataset.step<=this.step){this.step=+button.dataset.step;this.render();}});
      const renderers=[this.renderMode,this.renderTeams,this.renderCharacters,this.renderBuilds,this.renderAbilities,this.renderPerks,this.renderArena,this.renderModifiers,this.renderSummary];
      this.root.querySelector(".draft-stage").innerHTML=renderers[this.step].call(this);this.bindStage();
      this.root.querySelector("[data-draft-prev]").disabled=this.step===0;this.root.querySelector("[data-draft-next]").textContent=this.step===8?"INICIAR BATALHA →":"AVANÇAR →";
      this.root.querySelector(".draft-budget").innerHTML=`<span>ENTIDADES <b>${this.teamCount()}</b></span><span>ORÇAMENTO <b>${this.budget()}</b> / 1800</span><span>SEED <b>${esc(this.data.seed||"AUTOMÁTICA")}</b></span>`;
    }
    cards(items,selected,attribute="choice"){return `<div class="draft-card-grid">${items.map((item)=>`<button class="draft-card ${selected===item.id?"selected":""}" data-${attribute}="${item.id}"><small>${esc(item.label||item.category||"")}</small><b>${esc(item.name||item.label)}</b><span>${esc(item.description||"")}</span></button>`).join("")}</div>`;}
    renderMode(){return `<div class="draft-title"><small>01 · PLATAFORMA & FORMATO</small><h2>Escolha como lutar</h2><p>Orb Arena usa combate orbital; Stick Arena transforma o mesmo elenco em lutadores 2D.</p></div><div class="draft-card-grid game-mode-cards">${OA.GameModeRegistry.all().map((item)=>`<button class="draft-card ${this.data.gameModeId===item.id?"selected":""}" data-game-mode="${item.id}"><small>GAME MODE</small><b>${item.label}</b><span>${item.id==="stick"?"Plataformas, saltos, bloqueio e combos.":"Física orbital, ricochetes e Wall Boost."}</span></button>`).join("")}</div><div class="draft-title"><h2>Formato da partida</h2></div>${this.cards(Object.values(OA.MATCH_MODES),this.data.modeId,"mode")}`;}
    renderTeams(){const mode=this.mode();return `<div class="draft-title"><small>02 · EQUIPES</small><h2>Formação e controle</h2><p>A movimentação permanece automática nos dois modos. Em MANUAL, Skills e Ultimate aguardam seus comandos.</p></div><div class="team-preview">${mode.sides.map((size,index)=>`<article style="--team:${OA.TEAM_PRESETS[index].color}"><b>${OA.TEAM_PRESETS[index].emblem} ${OA.TEAM_PRESETS[index].label}</b><strong>${size} ORB${size>1?"S":""}</strong><span>${index===0?"Equipe do jogador":"Controle automático"}</span></article>`).join("")}</div><div class="form-grid"><label>Controle principal<select data-field="controlMode"><option ${this.data.controlMode==="AUTO"?"selected":""}>AUTO</option><option ${this.data.controlMode==="MANUAL"?"selected":""}>MANUAL</option></select></label><label>Friendly Fire<select data-field="friendlyFire"><option value="false">Desativado</option><option value="true" ${this.data.friendlyFire?"selected":""}>Ativado</option></select></label><label>Seed<input data-field="seed" value="${esc(this.data.seed||OA.Random.createSeed())}"></label></div>`;}
    characterOptions(selected){return OA.CharacterRegistry.all().map((item)=>`<option value="${item.id}" ${item.id===selected?"selected":""}>${esc(item.name)} · ${esc(item.class)}</option>`).join("");}
    renderCharacters(){return `<div class="draft-title"><small>03 · ELENCO</small><h2>Selecione os capitães</h2><p>Os demais slots recebem personagens distintos definidos pela seed.</p></div><div class="draft-versus"><label>CAPITÃO AZUL<select data-field="characterId">${this.characterOptions(this.data.characterId)}</select></label><b>VS</b><label>CAPITÃO VERMELHO<select data-field="enemyCharacterId">${this.characterOptions(this.data.enemyCharacterId)}</select></label></div>`;}
    renderBuilds(){const weapons=OA.WEAPONS.map((item)=>`<option value="${item.id}" ${item.id===this.data.weaponId?"selected":""}>${esc(item.name)} · ${item.kind}</option>`).join("");return `<div class="draft-title"><small>04 · BUILD</small><h2>Arma e identidade da Orb</h2></div><div class="form-grid"><label>Nome da build<input data-field="buildName" maxlength="48" value="${esc(this.data.buildName||"Protocolo V")}"></label><label>Arma<select data-field="weaponId">${weapons}</select></label><label>Duração<select data-field="durationPreset">${["short","standard","long","epic"].map((id)=>`<option value="${id}" ${id===this.data.durationPreset?"selected":""}>${id.toUpperCase()}</option>`).join("")}</select></label></div>`;}
    renderAbilities(){const active=OA.ABILITIES.filter((item)=>item.type==="active");return `<div class="draft-title"><small>05 · HABILIDADES</small><h2>Quatro skills + Ultimate</h2><p>Cooldown, cargas e autocast são reais durante o combate.</p></div><div class="ability-draft">${["active","secondary","tertiary","quaternary"].map((slot,index)=>`<label><span>SKILL ${index+1}</span><select data-ability-slot="${slot}"><option value="">Procedural</option>${active.map((item)=>`<option value="${item.id}" ${this.data.abilities[slot]===item.id?"selected":""}>${esc(item.name)} · ${item.cooldown}s</option>`).join("")}</select></label>`).join("")}</div>`;}
    renderPerks(){return `<div class="draft-title"><small>06 · PERKS</small><h2>Até quatro modificadores passivos</h2></div><div class="perk-draft">${OA.PERKS.map((item)=>`<label class="${this.data.perks.includes(item.id)?"selected":""}"><input type="checkbox" data-perk="${item.id}" ${this.data.perks.includes(item.id)?"checked":""}><b>${esc(item.name)}</b><span>${esc(item.tags.join(" · "))}</span></label>`).join("")}</div>`;}
    renderArena(){return `<div class="draft-title"><small>07 · ARENA</small><h2>Arena retangular escalável</h2></div><div class="form-grid"><label>Arena<select data-field="arenaId">${Object.values(OA.ARENA_DEFINITIONS).map((item)=>`<option value="${item.id}" ${item.id===this.data.arenaId?"selected":""}>${esc(item.name)}</option>`).join("")}</select></label><label>Tamanho<select data-field="arenaSize">${Object.values(OA.ARENA_SIZES).map((item)=>`<option value="${item.id}" ${item.id===this.data.arenaSize?"selected":""}>${esc(item.label)} · ${item.width}×${item.height}</option>`).join("")}</select></label></div><div class="arena-wire"><i></i><b>WALL BOOST</b><span>${esc((OA.ARENA_SIZES[this.data.arenaSize]||OA.ARENA_SIZES.small).label)}</span></div>`;}
    renderModifiers(){return `<div class="draft-title"><small>08 · REGRAS</small><h2>Modificadores da partida</h2><p>Até 12 combinações; conflitos são resolvidos pela última regra.</p></div><div class="modifier-grid">${OA.MATCH_MODIFIERS.map((item)=>`<label class="${this.data.modifiers.includes(item.id)?"selected":""}"><input type="checkbox" data-modifier="${item.id}" ${this.data.modifiers.includes(item.id)?"checked":""}><small>${esc(item.category)}</small><b>${esc(item.label)}</b><span>${esc(item.description)}</span></label>`).join("")}</div>`;}
    renderSummary(){const hero=OA.CharacterRegistry.get(this.data.characterId),enemy=OA.CharacterRegistry.get(this.data.enemyCharacterId),size=OA.ARENA_SIZES[this.data.arenaSize];return `<div class="draft-title"><small>09 · CONFIRMAÇÃO</small><h2>Resumo do protocolo</h2><p>Revise todas as regras antes de iniciar.</p></div><div class="draft-summary"><article><small>MODO</small><b>${esc(this.mode().label)}</b><span>${this.teamCount()} combatentes · ${esc(this.data.controlMode)}</span></article><article><small>CAPITÃES</small><b>${esc(hero?.name)} × ${esc(enemy?.name)}</b><span>${esc(this.data.weaponId)}</span></article><article><small>ARENA</small><b>${esc(size?.label)} · ${size?.width}×${size?.height}</b><span>${esc(this.data.arenaId)} · ${esc(this.data.durationPreset)}</span></article><article><small>MODIFICADORES</small><b>${this.data.modifiers.length}</b><span>${this.data.modifiers.map((id)=>OA.MATCH_MODIFIERS.find((item)=>item.id===id)?.label).filter(Boolean).join(" · ")||"Regras padrão"}</span></article></div>`;}
    bindStage(){
      this.root.querySelectorAll("[data-mode]").forEach((button)=>button.onclick=()=>{this.data.modeId=button.dataset.mode;const count=this.teamCount();this.data.arenaSize=count<=2?"small":count<=4?"medium":count<=7?"large":"huge";this.render();});
      this.root.querySelectorAll("[data-game-mode]").forEach((button)=>button.onclick=()=>{this.data.gameModeId=button.dataset.gameMode;this.render();});
      this.root.querySelectorAll("[data-field]").forEach((input)=>input.onchange=()=>{this.data[input.dataset.field]=input.dataset.field==="friendlyFire"?input.value==="true":input.value;this.render();});
      this.root.querySelectorAll("[data-ability-slot]").forEach((input)=>input.onchange=()=>{this.data.abilities[input.dataset.abilitySlot]=input.value||null;});
      this.root.querySelectorAll("[data-perk]").forEach((input)=>input.onchange=()=>{const id=input.dataset.perk;this.data.perks=input.checked?[...new Set([...this.data.perks,id])].slice(-4):this.data.perks.filter((item)=>item!==id);this.render();});
      this.root.querySelectorAll("[data-modifier]").forEach((input)=>input.onchange=()=>{const id=input.dataset.modifier;this.data.modifiers=input.checked?[...new Set([...this.data.modifiers,id])].slice(-12):this.data.modifiers.filter((item)=>item!==id);this.render();});
    }
    budget(){const character=OA.CharacterRegistry.get(this.data.characterId);return (this.app.balance.get(character?.id)||0)+(OA.weaponById(this.data.weaponId)?.damage||0)*5+this.data.perks.length*35+Object.values(this.data.abilities).filter(Boolean).length*55;}
    next(){if(this.step<8){this.step+=1;this.render();return;}this.launch();}
    save(){const result=this.app.storage.saveDraftPreset({name:this.data.buildName||`${this.mode().label} · ${this.data.characterId}`,data:structuredClone(this.data)});this.app.toast(result.ok?"Preset de draft salvo.":"Não foi possível salvar o preset.",result.ok?"info":"error");}
    launch(){const character=OA.CharacterRegistry.get(this.data.characterId)||OA.CharacterRegistry.get("echo"),build={gameModeId:this.data.gameModeId,characterId:character.id,name:this.data.buildName||character.name,weaponId:this.data.weaponId,abilities:{...this.data.abilities},perks:[...this.data.perks],controlMode:this.data.controlMode,arenaId:this.data.arenaId,durationPreset:this.data.durationPreset};const matchConfig={modeId:this.data.modeId,arenaId:this.data.arenaId,arenaSize:this.data.arenaSize,durationPreset:this.data.durationPreset,friendlyFire:this.data.friendlyFire,modifiers:[...this.data.modifiers],seed:this.data.seed||OA.Random.createSeed()};this.app.startBattle(build,"normal",matchConfig.seed,OA.getPhysicsPreset("arcade"),{gameModeId:this.data.gameModeId,mode:this.data.modeId,enemyCharacterId:this.data.enemyCharacterId,matchConfig});}
  }
  OA.DraftUI=DraftUI;
}());
